import React, { useState } from 'react';
import './quiz.css';
import ScreenOne from "./Screenone/ScreenOne"
import ScrenenTwo from "./Screentwo/ScreenTwo"
import ScreenThree from "./Screenthree/ScreenThree"
import ScreenFour from "./Screenfour/ScreenFour"
import ScreenFive from "./Screenfive/ScreenFive"
import ScreenSix from "./Screensix/ScreenSix"

const sections = [
  <ScreenOne />,
  "Content of Section 2",
  "Content of Section 3",
  "Content of Section 4",
  "Content of Section 5",
  "Content of Section 6",
];

const Quiz = () => {
  const [currentSection, setCurrentSection] = useState(0);

  const handleNext = () => {
    if (currentSection < sections.length - 1) {
      setCurrentSection(currentSection + 1);
    }
  };

  const handleBack = () => {
    if (currentSection > 0) {
      setCurrentSection(currentSection - 1);
    }
  };

  const handleFinish = () => {
    alert("Finished! Loading another component...");
  };

  return (
    <div className="container quiz">
      <div className="content" style={{ height: '200px' }}>
        {sections.map((section, index) => (
          <div
            key={index}
            className="content-section"
            style={{
              top: `${(index - currentSection) * 100}%`,
            }}
          >
            {section}
          </div>
        ))}
      </div>
      <div className="buttons">
        {currentSection > 0 && <button onClick={handleBack}>Back</button>}
        {currentSection < sections.length - 1 ? (
          <button onClick={handleNext}>Next</button>
        ) : (
          <button onClick={handleFinish}>Finish</button>
        )}
      </div>
    </div>
  );
}

export default Quiz;
